function createError(status, code, message) {
  return { error: { code, message } };
}

module.exports = { createError };

const crypto = require('node:crypto');

function generateId() {
  return crypto.randomUUID();
}

module.exports = { generateId };

const { generateId, createError } = require('../../lib/id'), require('../../lib/errors');
let projects = require('../projects/service').getProjects();

function addCommentToTask(projectId, taskId, data) {
  const project = projects.find(p => p.id === projectId);
  if (!project) return createError(404, 'NOT_FOUND', 'Project not found');
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) return createError(404, 'NOT_FOUND', 'Task not found');
  if (!data.message) return createError(400, 'INVALID_DATA', 'Message is required');
  const comment = { id: generateId(), message: data.message };
  task.comments = task.comments || [];
  task.comments.push(comment);
  return comment;
}

function getCommentsByTaskId(projectId, taskId) {
  const project = projects.find(p => p.id === projectId);
  if (!project) return createError(404, 'NOT_FOUND', 'Project not found');
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) return createError(404, 'NOT_FOUND', 'Task not found');
  return task.comments || [];
}

module.exports = { addCommentToTask, getCommentsByTaskId };

const express = require('express');
const router = express.Router();
const service = require('./service');

router.post('/', (req, res) => {
  const { projectId } = req.params;
  const data = req.body;
  const result = service.addMemberToProject(projectId, data);
  if (!result || result.error) return res.status(result?.error.code || 500).json(result);
  res.status(201).json(result);
});

module.exports = router;

const { createError } = require('../../lib/errors');
let projects = require('../projects/service').getProjects();

function addMemberToProject(projectId, data) {
  const project = projects.find(p => p.id === projectId);
  if (!project) return createError(404, 'NOT_FOUND', 'Project not found');
  if (!data.userId || !data.role) return createError(400, 'INVALID_DATA', 'UserId and role are required');
  const memberExists = project.members.some(m => m.userId === data.userId);
  if (memberExists) return createError(409, 'DUPLICATE_MEMBER', 'Member already exists in the project');
  const member = { userId: data.userId, role: data.role };
  project.members.push(member);
  return member;
}

module.exports = { addMemberToProject };

